import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { DatePipe, formatNumber } from "@angular/common";
import {
  Installments,
  LoanCancel,
  LoanRejRef,
} from "src/app/views/Models/Loan/LoanInfo";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { ReferencesService } from "src/app/core/services/references.service";
@Component({
  selector: "app-cancel-loan-rejection",
  templateUrl: "./cancel-loan-rejection.page.html",
  styleUrls: ["./cancel-loan-rejection.page.scss"],
})
export class CancelLoanRejectionPage implements OnInit {
  today = new Date();
  com_dec_date = "";
  application_key = "";
  pipe = new DatePipe("en-US");
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    private alertService: AlertService,
    private ReferencesService: ReferencesService
  ) {}

  showLoader: boolean = false;
  isSearching: boolean = true;
  SearchResult: SearchResult;
  cancelLoanForm: FormGroup;
  LoanCancel: LoanCancel;
  LoanInstallments: Installments[];
  isLoanCancelForm: boolean = false;
  LoanRejRef: LoanRejRef[];
  ngOnInit() {
    this.cancelLoanForm = this.formBuilder.group({
      client_key: [""],
      com_dec_date: ["", [Validators.required]],
      loan_rej_code: ["", [Validators.required]],
      application_key: ["", [Validators.required]],
      loan_notes: [""],
    });
  }
  NumberFormatStyle(number) {
    let result = formatNumber(Number(number), "en-US", "1.2-2");
    return result;
  }
  async clientSelected(event: SearchResult) {
    this.SearchResult = event;
    this.showLoader = true;

    this.isSearching = false;
    this.http
      .post(this.env.API_URL + "api/Loan/GetLoanCancelByLoanKey", {
        loan_key: event.loan_key.toString(),
      })
      .subscribe({
        next: (data) => {
          this.LoanCancel = data;
          let ChangedFormat = this.pipe.transform(this.today, "yyyy-MM-dd");
          this.com_dec_date = ChangedFormat;
          this.cancelLoanForm.patchValue({
            com_dec_date: this.com_dec_date,
            application_key: this.LoanCancel.application_key,
            loan_notes: this.LoanCancel.loan_notes,
          });

          this.isLoanCancelForm = true;
          this.showLoader = false;
        },
        error: (err) => {
          this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
    this.http
      .post(this.env.API_URL + "api/Loan/GetLoanInstallments", {
        loan_key: event.loan_key.toString(),
      })
      .subscribe({
        next: (data) => {
          this.LoanInstallments = data["installments"];
          this.isLoanCancelForm = true;
          this.showLoader = false;
        },
        error: (err) => {
          this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
    this.LoanRejRef = await this.ReferencesService.LoanRejRef();
  }
  checker(input: string) {
    return this.datepipe.transform(input, "yyyy-MM-dd");
  }
  clearForms() {
    this.LoanCancel = null;
    this.LoanInstallments = [];
    this.cancelLoanForm.reset();
    this.isSearching = true;
    this.isLoanCancelForm = false;
  }
  async formSubmit() {
    if (!this.cancelLoanForm.valid) {
      await this.alertService.showAlertError("يجب ادخال سبب الرفض", false);
    } else {
      if (await this.alertService.SaveAlert()) {
        this.showLoader = true;
        this.http
          .post(this.env.API_URL + "api/Loan/LoanCancel", {
            application_key: this.cancelLoanForm.value.application_key,
            com_dec_date: this.cancelLoanForm.value.com_dec_date,
            loan_rej_code: this.cancelLoanForm.value.loan_rej_code,
            loan_notes: this.cancelLoanForm.value.loan_notes,
            app_uuc: this.LoanCancel.uuc_client,
          })
          .subscribe({
            next: (data) => {
              this.clearForms();
              this.showLoader = false;
              this.alertService.showAlertConfirm("تم الغاء القرض", true);
            },
            error: (err) => {
              this.alertService.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    }
  }
}
